// JavaScript implementation for Frontend Development Core Principles Part 3A
async function handleExecution(payload) {
  try {
    const response = await fetch('/api/data', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload)
    });
    const data = await response.json();
    console.log('Frontend Development Core Principles Part 3A status:', data.success);
    return data;
  } catch (err) {
    console.error('Execution error:', err);
  }
}

handleExecution({ item: 'Frontend Development Core Principles Part 3A' });
